use void::ServerBuilder;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let server = ServerBuilder::new("127.0.0.1:25565")
        .motd("Tikkub Server".to_string())
        .favicon("data:image/png;base64,".to_string())
        .build()
        .await?;

    server.run().await
}
